sp_angular_provider.script:
/* Use this Directive to show an opening scene with a label, icon and content for Primary Asignee
//
// Copyrights belong to Discover Technologies LLC. © 2023 Discover Technologies LLC
// Special License Rights
//  The Government's rights to use, display, or disclose this software are restricted.
//  Any reproduction of computer software, computer software documentation,
//  or portions thereof marked with this legend must also reproduce the markings. 
// Script Continued Below
//-----------------------------------------------------------------------------------------------------
// 2.8.5 | 2023-11-28 | raj | Updates to make work for TemplateTask
// 2.8.5 | 2023-07-10 | raj | STRY0141856 - Stretch- PLACEHOLDER- Office Control
//
//-----------------------------------------------------------------------------------------------------
*/
function dtechItemMembers(getTemplateUrl, spModal, $timeout, $window) {
	var dtechDirective = {
		restrict: 'E',
		// replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way
		scope: {
			dtechChatEnabled: "<", // STRY0136617
			dtechIsModal: "<",
			dtechPopoverPlacement: '@?',
			dtechShowLabel: "<?",
			dtechTable: '@',
			dtechTaskSysId: '@',
			dtechToolTipOpen: "=?",
			dtechItemMembersObject: "=",
			dtechTaskTitle: "<?",
			dtechUserImageSize: '<',
			dtechHideHoverPanel: "<?",
			dtechMaxRowsToDisplay: "<",
			dtechImagesToDisplay: "=?",
			dtechIsTaskTree: "<?"
		},
		controller: directiveCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechItemMembers.html')
	};
	return dtechDirective;

	function directiveCtrl($scope, $attrs, $animate, dtechOrganizationalUser, dtechTaskService, dtechTemplateService) {
		var d = this;
		// have local per directive instead of global - TODO: get from a service
		var CONST_TEMP_WAIT_DURATION = 600;
		// STRY0139742 - Increase delaying when hover directives open; TODO: get from a service
		var CONST_POPOVER_DELAY = 1200;
		var CONST_SPINNER_DELAY = 500;

		d.chatEnabled = _chatEnabled;
		d.chatInfo = undefined; // this is loaded on hover or on chat click

		var isOverTooltip = false;
		var isClosing = false;

		// STRY0145237 - Directive - Duration code; 
		var parentMouseLeaveTimeouts = []; // added an array to collect each time mouse leave fires; need to cancel time-outs on destroy
		$scope.dtechToolTipOpen = false;
		d.enterTooltip = _enterTooltip;
		d.imageOffset=8; // this is default for 24 image size
		d.init = _init;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added
		d.initTooltip = _initTooltip;

		d.leaveTooltip = _leaveTooltip;
		d.openColabChatConversation = _openColabChatConversation;
		d.openModal = _openModal;
		d.openUserProfileModal = _openUserProfileModal;
		d.membersSpan = {};

		d.parentMouseLeave = _parentMouseLeave;

		// STRY0139742 - Increase delaying when hover directives open; 
		d.popoverDelay = CONST_POPOVER_DELAY;  // added to set popover-popup-delay in the Macro HTML

		d.openChat = _openChat;
		d.openChatAll = _openChatAll;

		d.popoverTemplate = $scope.dtechItemMembersObject.objectType + '-popover-assignment.html';

		d.showItemMembers = _showItemMembers;

		// STRY0136617
		function _chatEnabled() {
			return $scope.dtechChatEnabled;
		}

		function _openColabChatConversation(){
			alert("Comming sooon... Sidebar colab chat");
		}

		// when the user hovers over the tooltip set overtooltip flag
		function _enterTooltip() {
			isOverTooltip = true;
		}

		// init()
		// initialize the control, called from the Link function
		// gets a reference to the element
		function _init(rawAttrs) {

			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechPopoverPlacement)) {
				$scope.dtechPopoverPlacement = "auto";
			}

			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechShowLabel)) {
				$scope.dtechShowLabel = false;
			}

			// Set default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechTaskTitle)) {
				if($scope.dtechItemMembersObject){
					$scope.dtechTaskTitle = $scope.dtechItemMembersObject.itemMembersTitle;
				}
			}

			$scope.dtechToolTipOpen = 
				angular.isDefined($attrs.dtechToolTipOpen) ?
				$scope.$parent.$eval($attrs.dtechToolTipOpen) : false;

			$scope.dtechUserImageSize = 
				angular.isDefined($attrs.dtechUserImageSize) ?
				$scope.$parent.$eval($attrs.dtechUserImageSize) : 24;

			$scope.dtechHideHoverPanel = 
				angular.isDefined($attrs.dtechHideHoverPanel) ?
				$scope.$parent.$eval($attrs.dtechHideHoverPanel) : false;

			// if image size is not 24, set offset to the image size -9
			if($scope.dtechUserImageSize!=24){
				d.imageOffset=$scope.dtechUserImageSize - 9;
			}

			if (angular.isUndefined(rawAttrs.dtechMaxRowsToDisplay)) {
				$scope.dtechMaxRowsToDisplay = 5;
			}

			if (angular.isUndefined(rawAttrs.dtechImagesToDisplay)) {
				// images to display not passed in, defalut to maxRowsToDisplay
				$scope.dtechImagesToDisplay = $scope.dtechMaxRowsToDisplay;
			}

			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechIsTaskTree)) {
				$scope.dtechIsTaskTree = false;
			}

			_setMembersSpanDimensions();
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _initTooltip() {
			// if the user moved off of the parent before the tooltip opened, cancel the open
			if (isClosing == true) {
				_leaveTooltip();
				isClosing = false;
			}
		}

		function _leaveTooltip() {
			isOverTooltip = false;
			$scope.dtechToolTipOpen = false;

			// STRY0139742 - Increase delaying when hover directives open; set true
			isClosing = true;
		}

		// openChat()
		// this function is called from Template html
		// it is called when a user clicks on the link to send an email to a user
		function _openChat(event,member) {
			if(d.chatInfo && d.chatInfo.item_sys_id == $scope.dtechTaskSysId){
				_openChatWithInformation();	
			} else {
				// call to load chat info here
				// load profile
				var getChatInfoObj = {};
				getChatInfoObj.user_sys_ids = member.value;
				getChatInfoObj.item_sys_id = $scope.dtechTaskSysId;
				getChatInfoObj.table = $scope.dtechTable;
				dtechOrganizationalUser.getChatInfo(getChatInfoObj).then(function(response){
						_openChatResponseRecieved(response);
					});
			}
			event.stopPropagation();
		}

		// openChatAll()
		// this function is called from Template html
		// it is called when a user clicks on the link to send an email to a user
		function _openChatAll(event) {
			var arrUserIds = [];
			$scope.dtechItemMembersObject.members.filter(function(member){
				arrUserIds.push(member.value);
			});
			var userIds = arrUserIds.join(",");

			// call to load chat info here
			// load profile
			var getChatInfoObj = {};
			getChatInfoObj.user_sys_ids = userIds;
			getChatInfoObj.item_sys_id = $scope.dtechTaskSysId;
			getChatInfoObj.table = $scope.dtechTable;
			dtechOrganizationalUser.getChatInfo(getChatInfoObj).then(function(response){
					_openChatResponseRecieved(response);
				});
			event.stopPropagation();
		}

		function _openChatResponseRecieved(response){
			d.chatInfo = response;
			_openChatWithInformation();
		}

		function _openChatWithInformation(){
			if(d.chatInfo.deepLink){
				var chatData = d.chatInfo.deepLink;
				console.log(chatData);
				$window.open(chatData, '_blank');

			} else { 
				alert('Unable to load Chat.  Check Chat Configuration.');
				if(d.chatInfo.errorGettingLInk){
					console.error("Error Loading Link:" + d.chatInfo.errorGettingLInk);

				}
			}
/*
			var chatData = 'MSTeams:/l/chat/0/0?users=' + $scope.dtechParamObject.email;

			//var chatData = 'https://teams.microsoft.com/l/chat/0/0?users=' + $scope.dtechParamObject.email;
			if ($scope.dtechParamObject && $scope.dtechParamObject.emailSubject && $scope.dtechParamObject.emailSubject.length > 0) {
				chatData = chatData + '?message=' + $scope.dtechParamObject.chatMessageData;
			}
			$window.open(chatData, '_self');
*/			
		}

		// openModal()
		// this function is called from Template html
		// it is called when a user clicks on the open link
		function _openModal(event) {
			var title = $scope.dtechTaskTitle;
			if ($scope.dtechAssignmentObject.objectType=='templateTask' || 
				$scope.dtechAssignmentObject.objectType=='task') {
					// MWMTest; update
					x_153465_discovert.twJS.openAssignmentModal(spModal, title, $scope.dtechTable, $scope.dtechTaskSysId);

					// popover closes quickly and user is left watching the spinner before modal pops
					d.leaveTooltip();

					// modal is openened stop the row or cell click form raising
					event.stopPropagation();
			}
		}

		// openUserProfileModal()
		// this function is called from Template html
		// it is called when a user clicks on the Open User Profile link
		function _openUserProfileModal(event,sys_id) {
			x_153465_discovert.DTech_Out_of_Office.openUserProfileModal(spModal, sys_id);

			// popover closes quickly and user is left watching the spinner before modal pops
			d.leaveTooltip();

			// modal is openened stop the row or cell click form raising
			event.stopPropagation();

		}

		function _parentMouseLeave() {
			// STRY0145237 - Directive - Duration code changes to match design; 
			// we need to track each time the below fires so we cancel on destroy
			parentMouseLeaveTimeouts.push($timeout(function() {
				if(!isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_DURATION));
		}

		function _setMembersSpanDimensions(){
			var hoverPadding = 0;
			if(!$scope.dtechHideHoverPanel){
				hoverPadding = 20;
			}
			d.membersSpan = document.getElementById('membersSpan');
			d.membersSpan.style.height = $scope.dtechUserImageSize + hoverPadding + "px";
			d.membersSpan.style.width = $scope.dtechUserImageSize + (($scope.dtechImagesToDisplay-1)*(d.imageOffset))+ hoverPadding + "px";
		}

		function _showItemMembers() {
			$scope.dtechToolTipOpen = true;

			// STRY0139742 - Increase delaying when hover directives open; set false
			isClosing = false;

			var itemMembersObject = $scope.dtechItemMembersObject;
			// if no object load full object
			if(!itemMembersObject){
				itemMembersObject = {};
				itemMembersObject.taskId = $scope.dtechTaskSysId;
				itemMembersObject.loaded = false;
			// if no itemMembers on the object call back to get itemMembers
			} else if(!itemMembersObject.itemMembers){
				itemMembersObject.listLoaded = false;
			}

			if(!itemMembersObject.loaded || !itemMembersObject.listLoaded || itemMembersObject.taskId != $scope.dtechTaskSysId){
				$scope.dtechItemMembersObject.loaded = false;
				var dtechObject;
				if($scope.dtechItemMembersObject.objectType=='task'){
					if($scope.dtechIsTaskTree){
						// call to get itemMembers object and the lists object
						dtechTaskService.getItemMembersInformationTaskTree($scope.dtechTaskSysId).then(
							function(response){
								_responseRecieved(response);
							});
					} else {
						// call to get itemMembers object and the lists object
						dtechTaskService.getItemMembersInformation($scope.dtechTaskSysId).then(
							function(response){
								_responseRecieved(response);
							});
					}
				} else if($scope.dtechItemMembersObject.objectType=='templateTask'){
					dtechTemplateService.getItemMembersInformation($scope.dtechTaskSysId).then(
						function(response){
							_responseRecieved(response);
						});
				}
			}
		}

		function _responseRecieved(response){
			$timeout(function(){
				_setDTechObject(response.itemMembersInformation);
				}, CONST_SPINNER_DELAY);
		}

		function _setDTechObject(dtechObject){
			$scope.dtechItemMembersObject = dtechObject;
console.log("RJ - testing - scope.dtechItemMembersObject: " + JSON.stringify($scope.dtechItemMembersObject));
			$scope.dtechItemMembersObject.loaded = true;
		}

		// STRY0145237 - Directive - Duration code changes to match design; added
		$scope.$on("$destroy", function () {
			// we tracked each time mouse leave fired, now we can cancel each time-out and remove from the array
			angular.forEach(parentMouseLeaveTimeouts, function(item) {
				$timeout.cancel(item);
				parentMouseLeaveTimeouts.splice(parentMouseLeaveTimeouts.indexOf(item), 1);
			});
		});

	} // end function directiveCtrl

	// Link function links local methods to parent controller methods
	// see the list of events being monitored
	function link(scope, element, attrs, directiveCtrl) {
		// initialize the control
		directiveCtrl.init(attrs);
		scope.$on('$destroy',_destroy);
		// get the location of the element hovering over

		function _destroy() {
			element.remove();
		}
	}
}
